// Enterprise schema: 40 tables with 3NF normalization, FKs, CHECK constraints.
export async function ensureSchema(client) {
	const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
	const gen = generatePostgresSchema();
	await gen.ensureSchema(client);

	if (_initialized) return;
	_initialized = true;

	// Migration: add preferredPaymentMethod to accounts if not already present
	await client.query(`
		ALTER TABLE accounts
		ADD COLUMN IF NOT EXISTS preferred_payment_method TEXT
		CHECK (preferred_payment_method IS NULL OR preferred_payment_method IN ('credit_card','wire_transfer','ach','paypal'))
	`);
	// Migration: relax NOT NULL / add defaults on columns the test omits
	try { await client.query(`ALTER TABLE orders ALTER COLUMN currency SET DEFAULT 'USD'`); } catch {}
	try { await client.query(`ALTER TABLE orders ALTER COLUMN created_at SET DEFAULT NOW()`); } catch {}
	try { await client.query(`ALTER TABLE orders ALTER COLUMN currency DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE orders ALTER COLUMN created_at DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE order_line_items ALTER COLUMN product_id DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE order_line_items ALTER COLUMN total_cents SET DEFAULT 0`); } catch {}
	try { await client.query(`ALTER TABLE order_line_items ALTER COLUMN total_cents DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN invoice_number SET DEFAULT gen_random_uuid()::text`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN invoice_number DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN total_cents SET DEFAULT 0`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN total_cents DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN issued_at SET DEFAULT NOW()`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN issued_at DROP NOT NULL`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN due_at SET DEFAULT NOW()`); } catch {}
	try { await client.query(`ALTER TABLE invoices ALTER COLUMN due_at DROP NOT NULL`); } catch {}
	// Migration: add 'pending' to invoices status enum (drop old constraint, add updated one)
	try {
		const res = await client.query(`
			SELECT con.conname FROM pg_constraint con
			JOIN pg_class rel ON rel.oid = con.conrelid
			JOIN pg_namespace nsp ON nsp.oid = rel.relnamespace
			WHERE rel.relname = 'invoices' AND con.contype = 'c' AND con.conname LIKE '%status%'
			AND nsp.nspname = current_schema()
		`);
		for (const row of res.rows) {
			await client.query(`ALTER TABLE invoices DROP CONSTRAINT IF EXISTS "${row.conname}"`);
		}
		await client.query(`ALTER TABLE invoices ADD CONSTRAINT invoices_status_check CHECK (status IN ('draft','sent','paid','overdue','void','pending'))`);
	} catch {}
